---判断当前领地相关的信息是否能保存
local function checkManorAboutDataCanSave(player)
    local manorInfo = GameMatch:getUserManorInfo(player.userId)
    if not manorInfo then
        return nil
    end
    if manorInfo.isNotInPartyCreateOrOver == false then
        HostApi.log("manor cannot save isNotInPartyCreateOrOver " .. tostring(player.userId))
        return nil
    end
    if manorInfo.release_status ~= Define.manorRelese.Not then
        if manorInfo.isInRoomForceRelease == true then
            HostApi.log("manor cannot save isInRoomForceRelease " .. tostring(player.userId))
            return nil
        end
        if player.isReady then
            if player.manorIndex <= 0 then
                HostApi.log("manor cannot save when manor is in release_status and player's manorIndex error userId: " .. tostring(player.userId) .. " " .. player.manorIndex)
                return
            end
            if player.isNotInPartyCreateOrOver then
                if tostring(player.userId) == tostring(player.target_user_id) then
                    HostApi.log("manor cannot save when manor is in release_status check it ManorUserId: "
                            .. tostring(manorInfo.userId) .. " userId: " .. tostring(player.userId) .. " targetUserId: " .. tostring(player.target_user_id))
                else
                    HostApi.log("manor cannot save when manor is in release_status and player may be is visiting other  " .. tostring(player.userId) .. " " .. tostring(player.target_user_id))
                end
            else
                HostApi.log("manor cannot save when manor is in release_status and player is ready and player is in party create or over userId: " .. tostring(player.userId))
            end
        else
            HostApi.log("manor cannot save when manor is in release_status and player is not ready userId: " .. tostring(player.userId))
        end
        return nil
    end
    return manorInfo
end

