function DbUtil.initDataFromDB(userId, subKey, data)
    -- DBManager:addCache(userId, subKey, data)
    HostApi.log("initDataFromDB " .. tostring(userId) .. " " .. tostring(subKey))

    if subKey == DbUtil.TAG_PLAYER then
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            DBManager:addCache(userId, subKey, data)
            player:initDataFromDB(data)
            GameParty:sendPlayerPartyData(userId)
        end
    end

    if subKey == DbUtil.TAG_MANOR then

        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initManorInfoFromDB(data)
        end
    end

    if string.find(subKey, DbUtil.TAG_BLOCK_PRE) ~= nil then

        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initBlockFromDB(data, subKey)
        end
    end

    if subKey == DbUtil.TAG_MIAN_LINE then
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            DBManager:addCache(userId, subKey, data)
            player:initMainLineDataFromDB(data)
            player.taskController:init()
            player:checkAllChangeDataToMember()
        end
    end

    if subKey == DbUtil.TAG_CHEST then

        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initChestDataFromDB(data)
        end
    end

    if subKey == DbUtil.TAG_SHAREDATA then
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            DBManager:addCache(userId, subKey, data)
            player:initShareDataFromDB(data)
            player.taskController:init()
            player:checkAllChangeDataToMember()
            GameParty:sendPlayerPartyData(userId)
        end
    end

    if subKey == DbUtil.TAG_FURNACE then

        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initFurnaceDataFromDB(data)
        end
    end

    if subKey == DbUtil.TAG_SIGN then

        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initSignPostTextDataFromDB(data)
        end
    end

    if subKey == DbUtil.DIALOG_TIPS then
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            DBManager:addCache(userId, subKey, data)
            player:initDialogTipsDataFromDB(data)
        end
    end

    if subKey == DbUtil.TAG_ACTOR then
        local targetManorInfo = GameMatch:getUserManorInfo(userId)
        if targetManorInfo ~= nil then
            DBManager:addCache(userId, subKey, data)
            targetManorInfo:initActorFromDB(data)
        end
    end
end

function DbUtil.CanSavePlayerData(player, subKey)
    return DBManager:isLoadDataFinished(player.userId, subKey)
end

function DbUtil.savePlayerData(player, immediate)
    if player == nil then
        return
    end
    if not immediate then
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerGameData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerManorData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerBlockData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerMainLineData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerChestData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerShareData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerFurnaceData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerSignPostData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerDialogTipsData)
        SaveDBTaskQueue.addTask(player, DbUtil.SavePlayerActorData)
        return
    end
    SaveDBTaskQueue.clearTask(player.userId)
    DbUtil.SavePlayerGameData(player, immediate)
    DbUtil.SavePlayerManorData(player, immediate)
    DbUtil.SavePlayerBlockData(player, immediate)
    DbUtil.SavePlayerMainLineData(player, immediate)
    DbUtil.SavePlayerChestData(player, immediate)
    DbUtil.SavePlayerShareData(player, immediate)
    DbUtil.SavePlayerFurnaceData(player, immediate)
    DbUtil.SavePlayerSignPostData(player, immediate)
    DbUtil.SavePlayerDialogTipsData(player, immediate)
    DbUtil.SavePlayerActorData(player, immediate)
    -- log
    --LogShareDataKey(player)
    --player:LogInventoryInfo()
    --LogBlockKey(player)
end

function DbUtil.SavePlayerGameData(player, immediate)
    -- vistor not save
    local targetManorInfo = GameMatch:getUserManorInfo(player.userId)
    if targetManorInfo == nil then
        return
    end

    if not DbUtil.CanSavePlayerData(player, DbUtil.TAG_PLAYER) then
        return
    end

    local data = {}
    if player.respawnPos and
            player.respawnPos.x >= 0 and player.respawnPos.x <= GameConfig.manorMax and
            player.respawnPos.y >= 0 and player.respawnPos.y <= GameConfig.manorMax and
            player.respawnPos.z >= 0 and player.respawnPos.z <= GameConfig.manorMax then
        data.respawnPos = { x = player.respawnPos.x, y = player.respawnPos.y, z = player.respawnPos.z }
    else
        local pos = GameConfig:getOriginPosByManorIndex(player.manorIndex) or GameConfig:getInitPosByManorIndex(player.manorIndex)
        if pos then
            player:moveHome(pos, false)
            data.respawnPos = { x = player.respawnPos.x, y = player.respawnPos.y, z = player.respawnPos.z }
        else
            data.respawnPos = { x = GameConfig.manorMax / 2, y = GameConfig.manorMax, z = GameConfig.manorMax / 2 }
        end
    end
    data.oldExp = player.oldExp
    data.loginData = player.loginData
    data.giveLoveLastNum = player.giveLoveLastNum
    data.bulletin = player.bulletin
    DBManager:savePlayerData(player.userId, DbUtil.TAG_PLAYER, data, immediate)
end

