function DbUtil.SavePlayerBlockData(player, immediate)
    local targetManorInfo = checkManorAboutDataCanSave(player)
    if not targetManorInfo then
        return
    end

    local blockInfo = targetManorInfo.manorBlock
    local updateBlock = targetManorInfo.updateBlock
    local attachUpdateBlock = targetManorInfo.attachUpdateBlock
    local subKeyInfo = {}

    if updateBlock then
        for _, block in pairs(updateBlock) do
            local key = block.pos.x .. ":" .. block.pos.y .. ":" .. block.pos.z
            local value = block.id .. ":" .. block.meta
            local subKey = player:generateSubKey(key, value)
            if subKey then
                -- HostApi.log("SavePlayerBlockData updateBlock " .. subKey)
                if DbUtil.CanSavePlayerData(player, subKey) and not targetManorInfo.newKeyLock[subKey] then
                    if subKeyInfo[subKey] == nil then
                        subKeyInfo[subKey] = {}
                    end

                    subKeyInfo[subKey][tostring(key)] = tostring(value)
                end
            end
        end
    end

    if attachUpdateBlock then
        for _, block in pairs(attachUpdateBlock) do
            local rPos = targetManorInfo:aPosToRPos(block.aPos)
            local key = rPos.x .. ":" .. rPos.y .. ":" .. rPos.z
            local value = block.id .. ":" .. block.meta
            local subKey = player:generateSubKey(key, value)
            if subKey then
                -- HostApi.log("SavePlayerBlockData attachUpdateBlock " .. subKey)
                if DbUtil.CanSavePlayerData(player, subKey) and not targetManorInfo.newKeyLock[subKey] then
                    if subKeyInfo[subKey] == nil then
                        subKeyInfo[subKey] = {}
                    end

                    subKeyInfo[subKey][tostring(key)] = tostring(value)
                end
            end
        end
    end

    if blockInfo then
        for key, value in pairs(blockInfo) do
            local subKey = player:generateSubKey(key, value)
            if subKey then
                -- HostApi.log("SavePlayerBlockData blockInfo " .. subKey)
                if DbUtil.CanSavePlayerData(player, subKey) and not targetManorInfo.newKeyLock[subKey] then
                    if subKeyInfo[subKey] == nil then
                        subKeyInfo[subKey] = {}
                    end

                    subKeyInfo[subKey][tostring(key)] = tostring(value)
                end
            end
        end
    end

    local countAll = {}
    for subKey, data in pairs(subKeyInfo) do

        if countAll[subKey] == nil then
            countAll[subKey] = 0
        end

        local dbData = {}
        dbData.block = {}
        for key, value in pairs(data) do
            -- local dataStr = key .. ":" .. value
            -- table.insert(dbData.block, dataStr)
            dbData.block[key] = value
            countAll[subKey] = countAll[subKey] + 1
        end

        if targetManorInfo.logBlock[subKey] then
            if countAll[subKey] < targetManorInfo.logBlock[subKey] then
                HostApi.log("[SCRIPT_EXCEPTION] Block may be lost check it ! will not save this subKey: " .. tostring(player.userId) .. " " .. subKey)
            else
                DBManager:savePlayerData(player.userId, subKey, dbData, immediate)
            end
        else
            DBManager:savePlayerData(player.userId, subKey, dbData, immediate)
        end
        -- DBManager:savePlayerData(player.userId, subKey, dbData, immediate)
    end
end

function DbUtil.SavePlayerMainLineData(player, immediate)
    if not DbUtil.CanSavePlayerData(player, DbUtil.TAG_MIAN_LINE) or not DbUtil.CanSavePlayerData(player, DbUtil.TAG_SHAREDATA) then
        return
    end

    player.taskController:transformToPlayerTaskData(player)
    local data = {}
    data.progressesLevel = player.progressesLevel
    data.mainline_tasks = player.mainline_tasks
    data.dare_tasks = player.dare_tasks
    data.maxDareTimes = player.maxDareTimes
    data.curDareTimes = player.curDareTimes
    data.nextTaskTime = player.nextTaskTime
    data.LastLoginDate = player.LastLoginDate
    data.free_refresh_times = player.free_refresh_times
    data.dareIsUnLock = player.dareIsUnLock
    data.taskIsLandLevel = player.taskIsLandLevel

    DBManager:savePlayerData(player.userId, DbUtil.TAG_MIAN_LINE, data, immediate)
end

